#include <bits/stdc++.h>
using namespace std;

const int N=2e6+10;

struct Node{
    int son[26],len,fa;
}st[N];

int n,last=1,tot=1,f[N];
long long ans;
char s[N];
vector<int> e[N];

void extend(int c){
    int p=last,np=++tot;
    last=np;
    f[tot]=1;
    st[np].len=st[p].len+1;
    for(;p && !st[p].son[c];p=st[p].fa) st[p].son[c]=np;
    if(!p){
        st[np].fa=1;
        return;
    }
    int q=st[p].son[c];
    if(st[q].len==st[p].len+1)
        st[np].fa=q;
    else{
        int nq=++tot;
        for(int i=0;i<26;i++) st[nq].son[i]=st[q].son[i];
        st[nq].fa=st[q].fa;
        st[nq].len=st[p].len+1;
        st[q].fa=st[np].fa=nq;
        for(;p && st[p].son[c]==q;p=st[p].fa) st[p].son[c]=nq;
    }
}

void dfs(int x){
    for(int y:e[x]){
        dfs(y);
        f[x]+=f[y];
    }
    if(f[x]>1) ans=max(ans,1ll*st[x].len*f[x]);
}

int main(){
    scanf("%s",s);
    for(int i=0;s[i];i++)
        extend(s[i]-'a');
    for(int i=2;i<=tot;i++)
        e[st[i].fa].push_back(i);
    dfs(1);
    printf("%lld",ans);
    return 0;
}
